class Solution:
    def generateTrees(self, n: int) -> List[Optional[TreeNode]]:
        if n == 0: return []
        def build(lo, hi):
            if lo > hi: return [None]
            res = []
            for r in range(lo, hi + 1):
                for left in build(lo, r - 1):
                    for right in build(r + 1, hi):
                        res.append(TreeNode(r, left, right))
            return res
        return build(1, n)

